/* @module 0xf566ae0384fcec44757c16b7b6ef02de */
export default { name: '8ball', alias: ['magic8ball', '8b', '🎱'], category: 'games', description: 'Ask the magic 8-ball a question 🎱', async execute(sock, msg, args, PREFIX) { const chatId = msg.key.remoteJid; const question = args.join(' ').trim(); if (!question) { return sock.sendMessage(chatId, { text: `┌─⧭ *MAGIC 8-BALL* 🎱 ⧭─┐ │ ├─⧭ *Usage:* │ ${PREFIX}8ball <question> │ ├─⧭ *Examples:* │ • ${PREFIX}8ball Will I win today? │ • ${PREFIX}8ball Is Foxy the best? │ └─⧭🦊` }, { quoted: msg }); } const responses = [ "🎱 It is certain.", "🎱 It is decidedly so.", "🎱 Without a doubt.", "🎱 Yes definitely.", "🎱 You may rely on it.", "🎱 As I see it, yes.", "🎱 Most likely.", "🎱 Outlook good.", "🎱 Yes.", "🎱 Signs point to yes.", "🎱 Reply hazy, try again.", "🎱 Ask again later.", "🎱 Better not tell you now.", "🎱 Cannot predict now.", "🎱 Concentrate and ask again.", "🎱 Don't count on it.", "🎱 My reply is no.", "🎱 My sources say no.", "🎱 Outlook not so good.", "🎱 Very doubtful.", "🦊 Foxy says: Definitely yes!", "🦊 Foxy is busy, ask later.", "🦊 The fox whispers: Yes!", "🦊 Foxy shakes head: No.", "🦊 The fox nods: Absolutely!" ]; const randomResponse = responses[Math.floor(Math.random() * responses.length)]; await sock.sendMessage(chatId, { text: `┌─⧭ *MAGIC 8-BALL* 🎱 ⧭─┐ │ ├─⧭ *Question:* │ ${question} │ ├─⧭ *Answer:* │ ${randomResponse} │ └─⧭🦊` }, { quoted: msg }); await sock.sendMessage(chatId, { react: { text: "🎱", key: msg.key } }); } };